  bearing: number;
}

const ProceduralBus = () => (
  <group scale={1.5}>
    <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
      {/* Chassis */}
      <mesh position={[0, 0.4, 0]}>
