        <meshStandardMaterial color="#fbbf24" />
      </mesh>
      {/* Roof */}
      <mesh position={[0, 0.9, 0]}>
        <boxGeometry args={[0.9, 0.2, 2.2]} />
        <meshStandardMaterial color="#fcd34d" />
      </mesh>
      {/* Windows */}
      <mesh position={[0, 0.6, 0.2]}>
        <boxGeometry args={[1.02, 0.3, 1.8]} />
