      </mesh>
      <mesh position={[-0.3, 0.3, 1.25]}>
        <sphereGeometry args={[0.1, 16, 16]} />
        <meshStandardMaterial color="white" emissive="white" emissiveIntensity={2} />
      </mesh>
      {/* Wheels */}
      {[[-0.5, 0, 0.8], [0.5, 0, 0.8], [-0.5, 0, -0.8], [0.5, 0, -0.8]].map((pos, i) => (
