    ],
    path: [[76.4764, 13.2642], [76.4820, 13.2680], [76.4880, 13.2720]],
    liveLat: 13.2720,
    liveLng: 76.4880,
    actualLat: 13.2720,
    actualLng: 76.4880,
    heading: 0
