];

const INITIAL_ROUTES: BusRoute[] = [
  {
    id: 'R-101',
    name: 'Tiptur Campus Express',
    driver: 'Rajesh Kumar',
    driverPhone: '+91 98765 43210',
    numberPlate: 'KA-01-CB-1234',
    busId: 'B-1',
    eta: '12 mins',
    isLive: false,
    stops: [
      { id: '1', name: 'Tiptur Railway Station', time: '07:30 AM', status: 'passed', lat: 13.2642, lng: 76.4764 },
