interface ErrorBoundaryProps {
  fallback: ReactNode;
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
}

// Fix: Use React.Component explicitly and ensure the props and state types are correctly handled to satisfy the TypeScript compiler.
class ModelErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = { hasError: false };

  public static getDerivedStateFromError(_: any): ErrorBoundaryState {
    return { hasError: true };
  }

  public componentDidCatch(error: any) {
    console.error("3D Model Error:", error);
  }

  public render() {
    // Destructuring props and state to ensure the compiler recognizes them from the React.Component base class
    const { hasError } = this.state;
    const { fallback, children } = this.props;

    if (hasError) {
      return fallback;
    }
    return children;
  }
}

const GLTFBuss = ({ bearing }: { bearing: number }) => {
  const { scene } = useGLTF('https://vazxmixjsiawhamofees.supabase.co/storage/v1/object/public/models/bus/model.gltf');
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state, delta) => {
    if (groupRef.current) {
      const targetRotation = (bearing * Math.PI) / 180;
      groupRef.current.rotation.y = THREE.MathUtils.lerp(
        groupRef.current.rotation.y,
        -targetRotation,
        delta * 5
      );
    }
  });

  return (
    <group ref={groupRef} scale={0.5}>
      <primitive object={scene} />
      <Environment preset="city" />
    </group>
  );
};

export const BusModel: React.FC<BusModelProps> = ({ bearing }) => {
  return (
    <ModelErrorBoundary fallback={<ProceduralBus />}>
      <Suspense fallback={<ProceduralBus />}>
         <GLTFBuss bearing={bearing} />
      </Suspense>
    </ModelErrorBoundary>
  );
};

