                                <span className="text-xs font-black text-slate-300 font-mono">{stop.time}</span>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
            </motion.div>

            <AnimatePresence>
                {snapPoint === HIDDEN_Y && (
                    <motion.button
                        initial={{ scale: 0, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        exit={{ scale: 0, opacity: 0 }}
                        onClick={() => {
                            setSnapPoint(COLLAPSED_Y);
                            controls.start({ y: COLLAPSED_Y });
