      groupRef.current.rotation.y = THREE.MathUtils.lerp(
        groupRef.current.rotation.y,
        -targetRotation,
        delta * 5
      );
    }
  });

  return (
    <group ref={groupRef} scale={0.5}>
      <primitive object={scene} />
      <Environment preset="city" />
    </group>
  );
};

