const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [currentView, setCurrentView] = useState<ViewState>('TRACKING');
  const [userRole, setUserRole] = useState<'student' | 'admin' | 'driver'>('student');
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'CONNECTED' | 'DISCONNECTED' | 'RECONNECTING'>('DISCONNECTED');

  // Persistence Loading
  const loadStored = <T,>(key: string, fallback: T): T => {
    const stored = localStorage.getItem(key);
    if (!stored) return fallback;
    try {
      return JSON.parse(stored);
    } catch {
      return fallback;
    }
  };

  const [routes, setRoutes] = useState<BusRoute[]>(() => loadStored('bus_routes', INITIAL_ROUTES));
  const [buses, setBuses] = useState<Bus[]>(() => loadStored('bus_fleet', INITIAL_BUSES));
  const [drivers, setDrivers] = useState<Driver[]>(() => loadStored('bus_drivers', INITIAL_DRIVERS));
  const [students, setStudents] = useState<Student[]>(() => loadStored('bus_students', INITIAL_STUDENTS));

  const [activeRouteId, setActiveRouteId] = useState<string>(() => {
    const storedRoutes = loadStored('bus_routes', INITIAL_ROUTES);
    return storedRoutes.length > 0 ? storedRoutes[0].id : '';
  });

  const [userLocation, setUserLocation] = useState<[number, number] | null>(null);
  const [userHeading, setUserHeading] = useState<number>(0);
  const [gpsError, setGpsError] = useState<{ message: string; code: number; details?: string } | null>(null);
  const [retryCount, setRetryCount] = useState(0);

  // Persistence Saving - Local
  useEffect(() => { localStorage.setItem('bus_routes', JSON.stringify(routes)); }, [routes]);
  useEffect(() => { localStorage.setItem('bus_fleet', JSON.stringify(buses)); }, [buses]);
  useEffect(() => { localStorage.setItem('bus_drivers', JSON.stringify(drivers)); }, [drivers]);
  useEffect(() => { localStorage.setItem('bus_students', JSON.stringify(students)); }, [students]);

  // --- Automatic Route Assignment Logic ---
  // If data changes (e.g. from cloud), ensure Driver is still assigned to the correct route
  useEffect(() => {
    if (isLoggedIn && userRole === 'driver' && currentUser) {
      const bus = buses.find(b => b.driverId === currentUser.id);
      const route = routes.find(r => r.busId === bus?.id);
      if (route && route.id !== activeRouteId) {
        console.log(`­¤öä Auto-assigning Driver to Route: ${route.name}`);
        setActiveRouteId(route.id);
      }
    }
  }, [routes, buses, isLoggedIn, userRole, currentUser]);

  // --- Real-time Logic (Stabilized) ---

  // 1. Define handlers
  const handleBusUpdate = useCallback((data: BusUpdatePayload) => {
    // Prevent Echo: If I am the driver for Route X, ignore updates about Route X coming from the server
    if (userRole === 'driver' && activeRouteId === data.routeId) return;

    setRoutes(prev => prev.map(r => {
      if (r.id === data.routeId) {
        return {
          ...r,
          liveLat: data.lat,
          liveLng: data.lng,
          actualLat: data.lat, 
          actualLng: data.lng,
          heading: data.heading,
          isLive: data.isLive
        };
      }
      return r;
    }));
  }, [userRole, activeRouteId]);

  const handleConfigUpdate = useCallback((data: GlobalConfigPayload) => {
    // Admin is the Source of Truth; ignore inbound config updates to prevent race conditions
    if (userRole === 'admin') return; 

    console.log("Ōśü’ĖÅ Applying Global Cloud Config...");
    setIsCloudSyncing(true);

    // Update all entities
    if (data.routes) setRoutes(data.routes);
    if (data.buses) setBuses(data.buses);
    if (data.drivers) setDrivers(data.drivers);
    if (data.students) setStudents(data.students);

    setTimeout(() => setIsCloudSyncing(false), 2000);
  }, [userRole]);

  // 2. Create Refs for handlers
  const handleBusUpdateRef = useRef(handleBusUpdate);
  const handleConfigUpdateRef = useRef(handleConfigUpdate);

  useEffect(() => {
    handleBusUpdateRef.current = handleBusUpdate;
  }, [handleBusUpdate]);

  useEffect(() => {
    handleConfigUpdateRef.current = handleConfigUpdate;
  }, [handleConfigUpdate]);

  // 3. Connect to Network
  useEffect(() => {
    const disconnect = connectToRealtime(
      (data) => handleBusUpdateRef.current(data), 
      (data) => handleConfigUpdateRef.current(data),
      (status) => setConnectionStatus(status)
    );
    return () => disconnect();
  }, []);

  // 4. Admin Broadcasting (Sending ALL Data)
  const handleAdminUpdate = (
    type: 'routes' | 'buses' | 'drivers' | 'students',
    newData: any[]
  ) => {
    if (type === 'routes') setRoutes(newData as BusRoute[]);
    if (type === 'buses') setBuses(newData as Bus[]);
    if (type === 'drivers') setDrivers(newData as Driver[]);
    if (type === 'students') setStudents(newData as Student[]);

    publishGlobalConfig({
      routes: type === 'routes' ? newData as BusRoute[] : routes,
      buses: type === 'buses' ? newData as Bus[] : buses,
      drivers: type === 'drivers' ? newData as Driver[] : drivers,
      students: type === 'students' ? newData as Student[] : students,
    });
  };

  const startTracking = useCallback(() => {
    if (!navigator.geolocation) {
      setGpsError({ message: "Geolocation not supported", code: 0 });
      return () => {};
    }
    setGpsError(null);
    const watchId = navigator.geolocation.watchPosition(
      (position) => {
        const { latitude, longitude, heading } = position.coords;
        if (typeof latitude === 'number' && typeof longitude === 'number' && !isNaN(latitude) && !isNaN(longitude)) {
          setUserLocation([latitude, longitude]);
          if (heading && !isNaN(heading)) {
            setUserHeading(heading);
          }
          setGpsError(null);
        }
      },
      (error) => {
        let msg = "GPS Signal Weak";
        if (error.code === error.PERMISSION_DENIED) {
            msg = "Location Access Denied";
        }
        setGpsError({ message: msg, code: error.code });
      },
      // IMPORTANT: Aggressive GPS settings for driving mode
      // maximumAge: 0 forces the device to get a fresh position, never cache
      // timeout: 5000 ensures we don't hang, but keep retry cycle tight
      { enableHighAccuracy: true, maximumAge: 0, timeout: 5000 }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  useEffect(() => {
    const cleanup = startTracking();
    return cleanup;
  }, [startTracking, retryCount]);

  useEffect(() => {
    if (isLoggedIn && userRole === 'driver') {
      const handleOrientation = (event: DeviceOrientationEvent) => {
        let heading: number | null = null;
        if ((event as any).webkitCompassHeading) {
          heading = (event as any).webkitCompassHeading;
        } else if (event.alpha !== null) {
          heading = 360 - event.alpha;
        }
        if (heading !== null) {
          setUserHeading(heading);
        }
      };
      window.addEventListener('deviceorientation', handleOrientation);
      return () => window.removeEventListener('deviceorientation', handleOrientation);
    }
  }, [isLoggedIn, userRole]);

  // --- DRIVER LOCATION LOGIC (Fixed) ---

  // 1. Update LOCAL state so driver sees their own bus moving
  useEffect(() => {
    if (isLoggedIn && userRole === 'driver' && userLocation) {
      const [lat, lng] = userLocation;

      setRoutes(prev => prev.map(r => {
        if (r.id === activeRouteId) {
          // We assume if the driver is logged in and GPS is updating, they want to see themselves.
          // We update actual coords (for admin) and live coords (if live).
          return { 
            ...r, 
            actualLat: lat, 
            actualLng: lng,
            liveLat: r.isLive ? lat : r.liveLat, 
            liveLng: r.isLive ? lng : r.liveLng,
            heading: userHeading
          };
        }
        return r;
      }));
    }
  }, [isLoggedIn, userRole, userLocation, activeRouteId, userHeading]);

  // 2. Broadcast to NETWORK (Side Effect)
  // This is separated from the state update to ensure reliability
  useEffect(() => {
    if (isLoggedIn && userRole === 'driver' && userLocation) {
       // Find the CURRENT route state to check if we are live
       const currentRoute = routes.find(r => r.id === activeRouteId);

       if (currentRoute && currentRoute.isLive) {
          // console.log("­¤ōĪ Broadcasting Location:", userLocation);
          publishBusUpdate({
            routeId: currentRoute.id,
            lat: userLocation[0],
            lng: userLocation[1],
            heading: userHeading,
            isLive: true
          });
       }
    }
  }, [userLocation, userHeading, isLoggedIn, userRole, activeRouteId, routes]); 
  // 'routes' dependency ensures we have the latest 'isLive' status. 
  // Since 'userLocation' triggers the local update above, 'routes' will change, triggering this.

  const activeRoute = routes.find(r => r.id === activeRouteId) || routes[0];

  const handleToggleTracking = (status: boolean) => {
    // 1. Update Local State
    setRoutes(prev => prev.map(r => r.id === activeRouteId ? { ...r, isLive: status } : r));

    // 2. Broadcast Status Change immediately
    if (userLocation) {
        console.log(`­¤ōĪ Toggle Tracking: ${status}`);
        publishBusUpdate({
            routeId: activeRouteId,
            lat: userLocation[0],
            lng: userLocation[1],
            heading: userHeading,
            isLive: status
        });
    }
  };

  const handleRouteSwitch = (direction: 'next' | 'prev') => {
    const currentIndex = routes.findIndex(r => r.id === activeRouteId);
    let nextIndex = 0;
    if (direction === 'next') {
        nextIndex = (currentIndex + 1) % routes.length;
    } else {
        nextIndex = (currentIndex - 1 + routes.length) % routes.length;
    }
    setActiveRouteId(routes[nextIndex].id);
  };

  const handleLogin = (email: string, password?: string): boolean => {
    const normEmail = email.toLowerCase().trim();
    const normPass = password?.trim() || '';

    if (normEmail === 'admin@gmail.com' && (normPass === 'admin' || normPass === '123123')) {
      setUserRole('admin');
      setCurrentView('ADMIN');
      setCurrentUser({ name: 'Admin', email: 'admin@gmail.com' });
      setIsLoggedIn(true);
      return true;
    }

    const foundDriver = drivers.find(d => 
      d.email.toLowerCase().trim() === normEmail && 
      (d.password || '') === normPass
    );

    if (foundDriver) {
      setCurrentUser(foundDriver);
      setUserRole('driver');
      setCurrentView('TRACKING'); 
      const bus = buses.find(b => b.driverId === foundDriver.id);
      const route = routes.find(r => r.busId === bus?.id);
      if (route) setActiveRouteId(route.id);
      setIsLoggedIn(true);
      return true;
    }

    const foundStudent = students.find(s => 
      s.email.toLowerCase().trim() === normEmail && 
      (s.password || '') === normPass
    );

    if (foundStudent) {
      setCurrentUser(foundStudent);
      setUserRole('student');
      setCurrentView('TRACKING');
      if (foundStudent.assignedRouteId) {
        setActiveRouteId(foundStudent.assignedRouteId);
      }
      setIsLoggedIn(true);
      return true;
    }

    return false;
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
    setCurrentView('TRACKING');
    setUserRole('student');
  };

  const handleReloadGps = () => {
    setUserLocation(null);
    setRetryCount(prev => prev + 1);
  };

  const resetAllData = () => {
    if (window.confirm("This will delete all custom routes and data. Continue?")) {
      setRoutes(INITIAL_ROUTES);
      setBuses(INITIAL_BUSES);
      setDrivers(INITIAL_DRIVERS);
      setStudents(INITIAL_STUDENTS);
      localStorage.clear();
      window.location.reload();
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'TRACKING':
        return <MapInterface 
          route={activeRoute} 
          userLocation={userLocation} 
          userRole={userRole}
          onToggleTracking={handleToggleTracking}
          onLogout={handleLogout}
          onSwitchRoute={handleRouteSwitch}
        />;
      case 'CHAT':
        return <AIChatbot />;
      case 'ADMIN':
        return <AdminDashboard 
          routes={routes} 
          buses={buses} 
          drivers={drivers}
          students={students}
          onUpdateRoutes={(d) => handleAdminUpdate('routes', d)} 
          onUpdateBuses={(d) => handleAdminUpdate('buses', d)} 
          onUpdateDrivers={(d) => handleAdminUpdate('drivers', d)}
          onUpdateStudents={(d) => handleAdminUpdate('students', d)}
          onLogout={handleLogout} 
          userLocation={userLocation} 
          onResetData={resetAllData}
        />;
      case 'DRIVER':
        return <DriverDashboard 
          driver={currentUser}
          bus={buses.find(b => b.driverId === currentUser?.id)}
          route={activeRoute} 
          onLogout={handleLogout} 
        />;
      case 'PROFILE':
        return (
          <div className="flex flex-col h-full bg-slate-50 items-center justify-center p-8">
            <div className="bg-white p-10 rounded-[2.5rem] shadow-xl border border-slate-100 flex flex-col items-center w-full max-w-sm">
              <div className="w-24 h-24 bg-yellow-400 rounded-3xl flex items-center justify-center mb-6 shadow-lg"><User className="w-12 h-12 text-slate-900" /></div>
              <h2 className="text-2xl font-black text-slate-900 mb-1 capitalize">{currentUser?.name || userRole}</h2>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-8">{currentUser?.email || 'Logged In'}</p>
              <button 
                onClick={handleLogout} 
                className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-black text-xs uppercase flex items-center justify-center gap-3 active:scale-95 transition-transform"
              >
                <LogOut className="w-4 h-4" /> Log Out
              </button>
            </div>
          </div>
        );
      default:
        return <MapInterface route={activeRoute} userLocation={userLocation} userRole={userRole} onToggleTracking={handleToggleTracking} onLogout={handleLogout} />;
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col bg-slate-50 overflow-hidden font-inter">
      {/* Network Status Indicator */}
      <div className={`absolute top-0 left-0 right-0 h-1 z-[5000] ${connectionStatus === 'CONNECTED' ? 'bg-green-500' : connectionStatus === 'RECONNECTING' ? 'bg-yellow-500' : 'bg-red-500'}`} />

      {!isLoggedIn ? (
        <LoginPage onLogin={handleLogin} />
      ) : (
        <>
          <main className="flex-1 relative overflow-hidden">
             {/* Connection Status Toast */}
             <AnimatePresence>
              {connectionStatus !== 'CONNECTED' && (
                 <motion.div initial={{ y: -50 }} animate={{ y: 0 }} exit={{ y: -50 }} className="absolute top-4 left-0 right-0 flex justify-center z-[4000]">
                    <div className="bg-slate-900/90 backdrop-blur text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 shadow-lg">
                       {connectionStatus === 'DISCONNECTED' ? <WifiOff className="w-3 h-3 text-red-400" /> : <Wifi className="w-3 h-3 text-yellow-400 animate-pulse" />}
                       {connectionStatus === 'DISCONNECTED' ? 'Offline - Trying to connect...' : 'Connecting to Server...'}
                    </div>
                 </motion.div>
              )}
             </AnimatePresence>

            <AnimatePresence>
              {gpsError && (
                <motion.div initial={{ y: -50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: -50, opacity: 0 }} className="absolute top-20 left-4 right-4 z-[3000]">
                  <div className="bg-white p-5 rounded-3xl shadow-2xl border border-red-50 flex items-center gap-4">
                    <RefreshCw className="w-5 h-5 text-red-500 cursor-pointer hover:rotate-180 transition-transform duration-500" onClick={handleReloadGps} />
                    <div className="flex-1 text-sm font-bold text-slate-900">{gpsError.message}</div>
                  </div>
                </motion.div>
              )}
               {isCloudSyncing && (
                <motion.div initial={{ y: -50, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: -50, opacity: 0 }} className="absolute top-20 left-4 right-4 z-[3000]">
                  <div className="bg-blue-500 p-5 rounded-3xl shadow-2xl border border-blue-400 flex items-center gap-4">
                    <CloudLightning className="w-5 h-5 text-white animate-pulse" />
                    <div className="flex-1 text-sm font-bold text-white">Updating App Data...</div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
            {renderView()}
          </main>
          <BottomNav currentView={currentView} setView={setCurrentView} userRole={userRole} />
        </>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { BusRoute } from '../types.ts';
import { Phone, ShieldAlert, Clock, Bus, UserCircle, Crosshair, MapPin, Power, Navigation, SignalHigh, Eye, EyeOff, LogOut, Navigation2, Compass, ChevronLeft, ChevronRight } from 'lucide-react';
import * as maplibregl from 'maplibre-gl';
import { motion, useAnimation, PanInfo, AnimatePresence } from 'framer-motion';

interface MapInterfaceProps {
  route: BusRoute;
  userLocation: [number, number] | null;
  userRole?: string;
  onToggleTracking?: (status: boolean) => void;
  onLogout?: () => void;
  onSwitchRoute?: (direction: 'next' | 'prev') => void;
}

const MapInterface: React.FC<MapInterfaceProps> = ({ route, userLocation, userRole, onToggleTracking, onLogout, onSwitchRoute }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [centerTarget, setCenterTarget] = useState<'bus' | 'user'>('bus');
  const [bearing, setBearing] = useState(0);
  const [isHeadingUp, setIsHeadingUp] = useState(false);
  const mapRef = useRef<maplibregl.Map | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const busMarkerRef = useRef<maplibregl.Marker | null>(null);
  const userMarkerRef = useRef<maplibregl.Marker | null>(null);
  const stopMarkersRef = useRef<maplibregl.Marker[]>([]);
  const prevCoordsRef = useRef<[number, number] | null>(null);
  const lastUpdateRef = useRef<number>(0);
  const controls = useAnimation();

  // Animation Refs
  const currentBusPos = useRef<[number, number] | null>(null);
  const targetBusPos = useRef<[number, number] | null>(null);
  const animationFrameRef = useRef<number>(0);

  const currentStopIndex = route.stops.findIndex(s => s.status === 'current');
  const activeIndex = currentStopIndex !== -1 ? currentStopIndex : 0;

  const DEFAULT_LNG_LAT: [number, number] = [76.4764, 13.2642];

  const isValidCoord = (lat: any, lng: any) => 
    typeof lat === 'number' && typeof lng === 'number' && !isNaN(lat) && !isNaN(lng);

  // Admin and Driver see the ACTUAL location (raw GPS).
  // Students/Parents see the LIVE location (which freezes when tracking is off).
  const busLngLat: [number, number] = 
    (userRole === 'driver' || userRole === 'admin')
      ? (isValidCoord(route.actualLat, route.actualLng) ? [route.actualLng!, route.actualLat!] : DEFAULT_LNG_LAT)
      : (isValidCoord(route.liveLat, route.liveLng) ? [route.liveLng!, route.liveLat!] : DEFAULT_LNG_LAT);

  // Dynamic Snap Points based on Screen Height
  const screenHeight = typeof window !== 'undefined' ? window.innerHeight : 800;

  const EXPANDED_Y = 0; // Snap to very top
  // Collapsed: Roughly in the middle-bottom
  const COLLAPSED_Y = userRole === 'driver' ? screenHeight - 200 : screenHeight - 380;
  // Minimized: Just a small handle visible above the 80px BottomNav
  const MINIMIZED_Y = screenHeight - 110; 
  // Hidden: Completely off-screen
  const HIDDEN_Y = screenHeight;

  // Track the current snap position to correctly calculate drag offsets
  const [snapPoint, setSnapPoint] = useState(COLLAPSED_Y);

  const calculateBearing = (start: [number, number], end: [number, number]) => {
    const startLat = (start[1] * Math.PI) / 180;
    const startLng = (start[0] * Math.PI) / 180;
    const endLat = (end[1] * Math.PI) / 180;
    const endLng = (end[0] * Math.PI) / 180;

    const y = Math.sin(endLng - startLng) * Math.cos(endLat);
    const x = Math.cos(startLat) * Math.sin(endLat) -
              Math.sin(startLat) * Math.cos(endLat) * Math.cos(endLng - startLng);
    const b = (Math.atan2(y, x) * 180) / Math.PI;
    return (b + 360) % 360;
  };

  // Linear Interpolation Helper
  const lerp = (start: number, end: number, factor: number) => {
    return start + (end - start) * factor;
  };

  useEffect(() => {
    if (!containerRef.current) return;

    const map = new maplibregl.Map({
      container: containerRef.current!,
      style: 'https://tiles.openfreemap.org/styles/liberty',
      center: busLngLat,
      zoom: 17.5,
      pitch: 0, 
      bearing: 0,
      antialias: true,
      attributionControl: false,
      fadeDuration: 0,
    });

    map.once('styledata', () => setIsLoading(false));

    map.on('load', () => {
      map.addLayer({
        'id': '3d-buildings',
        'source': 'openmaptiles',
        'source-layer': 'building',
        'type': 'fill-extrusion',
        'minzoom': 15,
        'paint': {
          'fill-extrusion-color': '#f1f5f9',
          'fill-extrusion-height': ['get', 'render_height'],
          'fill-extrusion-base': ['get', 'render_min_height'],
          'fill-extrusion-opacity': 0.6
        }
      });

      if (route.path && route.path.length > 0) {
        map.addSource('bus-path', {
          type: 'geojson',
          data: { type: 'Feature', properties: {}, geometry: { type: 'LineString', coordinates: route.path } }
        });
        map.addLayer({
          id: 'bus-path-glow',
          type: 'line',
          source: 'bus-path',
          layout: { 'line-join': 'round', 'line-cap': 'round' },
          paint: { 'line-color': '#fbbf24', 'line-width': 12, 'line-opacity': 0.1, 'line-blur': 4 }
        });
        map.addLayer({
          id: 'bus-path-layer',
          type: 'line',
          source: 'bus-path',
          layout: { 'line-join': 'round', 'line-cap': 'round' },
          paint: { 'line-color': '#fbbf24', 'line-width': 4, 'line-opacity': 0.6 }
        });
      }

      updateStopMarkers(map);
    });

    mapRef.current = map;
    return () => { 
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
        if (mapRef.current) mapRef.current.remove(); 
    };
  }, []); // Only run once on mount

  // Update Route Path when route changes
  useEffect(() => {
    const map = mapRef.current;
    if (!map || !map.getStyle() || !route.path) return;

    const source = map.getSource('bus-path') as maplibregl.GeoJSONSource;
    if (source) {
        source.setData({ 
            type: 'Feature', 
            properties: {}, 
            geometry: { type: 'LineString', coordinates: route.path } 
        });
    }
    updateStopMarkers(map);
  }, [route.id, route.path]); // Re-run when route changes

  const updateStopMarkers = (mapInstance: maplibregl.Map) => {
    stopMarkersRef.current.forEach(m => m.remove());
    stopMarkersRef.current = route.stops.map((stop, idx) => {
      const el = document.createElement('div');
      el.className = `w-6 h-6 rounded-full border-2 border-white shadow-lg flex items-center justify-center text-[9px] font-black text-white ${stop.status === 'passed' ? 'bg-slate-400' : stop.status === 'current' ? 'bg-yellow-500 ring-4 ring-yellow-500/20' : 'bg-blue-500'}`;
      el.innerText = (idx + 1).toString();
      return new maplibregl.Marker({ element: el }).setLngLat([stop.lng, stop.lat]).addTo(mapInstance);
    });
  };

  // 1. Handle Map Mode Transitions (Toggle)
  useEffect(() => {
    const map = mapRef.current;
    if (!map || !map.getStyle()) return;

    if (isHeadingUp) {
      map.flyTo({ bearing: bearing, center: currentBusPos.current || busLngLat, pitch: 60, zoom: 19, duration: 1500 });
    } else {
      map.flyTo({ bearing: 0, pitch: 0, zoom: 17.5, duration: 1500 });
    }
  }, [isHeadingUp]);


  const toggleHeadingMode = () => {
    setIsHeadingUp(prev => !prev);
  };

  // --- SMOOTH INTERPOLATION LOOP ---
  // Instead of jumping the marker, we smoothly animate it to the new target
  useEffect(() => {
     // Set new target whenever props change
     targetBusPos.current = busLngLat;
     if (!currentBusPos.current) {
        currentBusPos.current = busLngLat;
     }
  }, [busLngLat]);

  useEffect(() => {
     const animate = () => {
        if (currentBusPos.current && targetBusPos.current && busMarkerRef.current && mapRef.current) {
            const [curLng, curLat] = currentBusPos.current;
            const [targetLng, targetLat] = targetBusPos.current;

            // Simple LERP: Move 10% of the way to target per frame
            // This creates a smooth slide effect even if updates are 1s apart
            const factor = 0.08; 
            const newLng = lerp(curLng, targetLng, factor);
            const newLat = lerp(curLat, targetLat, factor);

            // Check if we are close enough to stop unnecessary calc (optimization)
            if (Math.abs(newLng - targetLng) > 0.000001 || Math.abs(newLat - targetLat) > 0.000001) {
                currentBusPos.current = [newLng, newLat];

                // Update Marker Visuals
                busMarkerRef.current.setLngLat([newLng, newLat]);

                // Update Camera if tracking bus
                if (isHeadingUp && centerTarget === 'bus') {
                     mapRef.current.easeTo({
                         center: [newLng, newLat],
                         bearing: bearing,
                         duration: 0, // Instant update for camera frame
                         easing: t => t
                     });
                }
            }
        }
        animationFrameRef.current = requestAnimationFrame(animate);
     };

     animationFrameRef.current = requestAnimationFrame(animate);

     return () => {
         if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
     };
  }, [isHeadingUp, centerTarget, bearing]);


  // Update Bus Marker Creation & Bearing Calculation
  useEffect(() => {
    const map = mapRef.current;
    if (!map || isLoading) return;

    if (isValidCoord(busLngLat[1], busLngLat[0])) {

      let currentBearing = bearing;

      if (typeof route.heading === 'number') {
        currentBearing = route.heading;
        if (Math.abs(currentBearing - bearing) > 1) {
          setBearing(currentBearing);
        }
      } else if (prevCoordsRef.current) {
        const newBearing = calculateBearing(prevCoordsRef.current, busLngLat);
        // Only update bearing if moving significantly to avoid jitter
        if (Math.abs(newBearing - bearing) > 10) {
          currentBearing = newBearing;
          setBearing(newBearing);
        }
      }

      prevCoordsRef.current = busLngLat;

      const getRealisticBusContent = (isLive: boolean | undefined) => `
            <div class="relative filter drop-shadow-xl">
               <div class="w-10 h-24 bg-gradient-to-b from-yellow-300 via-yellow-400 to-yellow-500 rounded-xl border border-yellow-600/30 relative z-10 overflow-hidden shadow-[inset_0_2px_10px_rgba(255,255,255,0.3)]">
                  <!-- Windshield -->
                  <div class="w-full h-6 bg-slate-800 mt-2 relative border-b border-slate-700">
                     <div class="absolute inset-0 bg-gradient-to-tr from-transparent via-white/10 to-transparent"></div>
                     <div class="absolute bottom-0 left-2 w-3 h-0.5 bg-slate-600 origin-left -rotate-12"></div>
                     <div class="absolute bottom-0 right-2 w-3 h-0.5 bg-slate-600 origin-right rotate-12"></div>
                  </div>
                  <div class="mx-auto w-6 h-8 border border-yellow-600/10 bg-yellow-400/30 rounded mt-3"></div>
                  <div class="mx-auto w-5 h-5 border border-yellow-600/10 bg-yellow-400/30 rounded-full mt-4"></div>
                  <div class="absolute bottom-1 w-full h-2 bg-slate-800/90"></div>
                  <div class="absolute bottom-0.5 left-1 w-2 h-1 bg-red-500 rounded-sm"></div>
                  <div class="absolute bottom-0.5 right-1 w-2 h-1 bg-red-500 rounded-sm"></div>
               </div>
               <div class="absolute top-6 -left-1.5 w-1.5 h-3 bg-slate-800 rounded-l-md border-r border-slate-600"></div>
