    const currentY = snapPoint + offset.y;
    let nearest = snapPoint;
    const SNAP_THRESHOLD = 120;

    if (Math.abs(velocity.y) > 400) {
      if (velocity.y > 0) {
        if (snapPoint === EXPANDED_Y) nearest = COLLAPSED_Y;
        else if (snapPoint === COLLAPSED_Y) nearest = MINIMIZED_Y;
